import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { motion } from 'framer-motion';
import { Bell, Dumbbell, Salad, ShoppingBag, Clock, CheckCircle, AlertCircle } from 'lucide-react';
import { useAuth } from '../../context/AuthContext';
import API from '../../utils/api';

export default function MemberDashboard() {
  const { user } = useAuth();
  const [notifications, setNotifications] = useState([]);

  useEffect(() => {
    API.get('/notifications').then(r => setNotifications(r.data.slice(0, 5))).catch(() => {});
  }, []);

  const daysLeft = user?.membershipEnd
    ? Math.ceil((new Date(user.membershipEnd) - new Date()) / (1000 * 60 * 60 * 24))
    : null;

  const membershipProgress = () => {
    if (!user?.membershipStart || !user?.membershipEnd) return 0;
    const total = new Date(user.membershipEnd) - new Date(user.membershipStart);
    const elapsed = new Date() - new Date(user.membershipStart);
    return Math.min(100, Math.max(0, (elapsed / total) * 100));
  };

  return (
    <div className="min-h-screen bg-[#0a0a0f] pt-20">
      <div className="max-w-5xl mx-auto px-6 py-10">
        {/* Header */}
        <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} className="mb-8">
          <h1 className="gym-font text-4xl text-white mb-1">
            Welcome, <span className="gradient-text">{user?.name?.split(' ')[0]}</span> 💪
          </h1>
          <p className="text-gray-400">Track your membership, workouts, and nutrition</p>
        </motion.div>

        {/* Membership Card */}
        <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.1 }}
          className="glass rounded-2xl p-6 mb-6 border border-orange-500/20">
          <div className="flex items-start justify-between mb-4">
            <div>
              <div className="text-gray-400 text-xs uppercase tracking-wider mb-1">Membership</div>
              <h2 className="text-white font-bold text-xl capitalize">{user?.membershipPlan} Plan</h2>
            </div>
            <span className={`text-xs px-3 py-1 rounded-full font-semibold capitalize ${
              user?.membershipStatus === 'active' ? 'bg-green-500/20 text-green-400' :
              user?.membershipStatus === 'expired' ? 'bg-red-500/20 text-red-400' : 'bg-yellow-500/20 text-yellow-400'
            }`}>{user?.membershipStatus}</span>
          </div>

          {daysLeft !== null && (
            <>
              <div className="flex justify-between text-xs text-gray-400 mb-2">
                <span>Progress</span>
                <span className={daysLeft <= 3 ? 'text-red-400 font-bold' : daysLeft <= 7 ? 'text-yellow-400 font-bold' : 'text-gray-300'}>
                  {daysLeft > 0 ? `${daysLeft} days remaining` : 'Expired'}
                </span>
              </div>
              <div className="w-full bg-gray-800 rounded-full h-2 mb-4">
                <div className="bg-gradient-to-r from-orange-500 to-red-500 h-2 rounded-full transition-all duration-500"
                  style={{ width: `${membershipProgress()}%` }} />
              </div>
            </>
          )}

          {daysLeft !== null && daysLeft <= 7 && daysLeft > 0 && (
            <div className="flex items-center gap-2 bg-yellow-500/10 border border-yellow-500/20 rounded-lg p-3 mb-4">
              <AlertCircle size={16} className="text-yellow-400" />
              <span className="text-yellow-300 text-sm">Your membership expires in {daysLeft} day(s). Please renew soon!</span>
            </div>
          )}

          {user?.membershipEnd && (
            <div className="flex gap-6 text-xs text-gray-400">
              {user.membershipStart && <span>Start: <span className="text-white">{new Date(user.membershipStart).toLocaleDateString()}</span></span>}
              <span>End: <span className="text-white">{new Date(user.membershipEnd).toLocaleDateString()}</span></span>
              {user.feeAmount && <span>Fee: <span className="text-orange-400">₹{user.feeAmount}</span></span>}
            </div>
          )}
        </motion.div>

        {/* Quick actions */}
        <div className="grid grid-cols-1 sm:grid-cols-3 gap-4 mb-8">
          {[
            { icon: <Dumbbell size={24} className="text-orange-400" />, label: 'View Exercises', path: '/exercises', color: 'hover:border-orange-500/30' },
            { icon: <Salad size={24} className="text-green-400" />, label: 'My Diet Plans', path: '/diet', color: 'hover:border-green-500/30' },
            { icon: <ShoppingBag size={24} className="text-blue-400" />, label: 'Supplement Store', path: '/store', color: 'hover:border-blue-500/30' },
          ].map((a, i) => (
            <motion.div key={i} initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.2 + i * 0.1 }}>
              <Link to={a.path} className={`glass rounded-xl p-5 flex items-center gap-4 transition-all ${a.color} group`}>
                <div className="w-12 h-12 bg-white/5 rounded-xl flex items-center justify-center group-hover:scale-110 transition-transform">
                  {a.icon}
                </div>
                <div>
                  <div className="text-white font-semibold">{a.label}</div>
                  <div className="text-gray-500 text-xs">Tap to explore</div>
                </div>
              </Link>
            </motion.div>
          ))}
        </div>

        {/* Notifications */}
        <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.5 }}
          className="glass rounded-xl p-5">
          <div className="flex items-center justify-between mb-4">
            <h2 className="text-white font-semibold flex items-center gap-2"><Bell size={18} className="text-orange-400" /> Recent Notifications</h2>
            <Link to="/notifications" className="text-orange-400 text-xs hover:underline">View all →</Link>
          </div>
          {notifications.length === 0 ? (
            <div className="flex flex-col items-center py-8 text-gray-500">
              <CheckCircle size={32} className="text-green-400 mb-2" />
              <span className="text-sm">No notifications</span>
            </div>
          ) : (
            <div className="space-y-3">
              {notifications.map(n => (
                <div key={n._id} className={`flex items-start gap-3 p-3 rounded-lg border ${n.isRead ? 'border-white/5' : 'border-orange-500/20 bg-orange-500/5'}`}>
                  <div className={`w-2 h-2 rounded-full mt-2 flex-shrink-0 ${n.isRead ? 'bg-gray-600' : 'bg-orange-500'}`} />
                  <div>
                    <div className="text-white text-sm font-semibold">{n.title}</div>
                    <div className="text-gray-400 text-xs mt-0.5">{n.message}</div>
                    <div className="text-gray-600 text-xs mt-1">{new Date(n.createdAt).toLocaleString()}</div>
                  </div>
                </div>
              ))}
            </div>
          )}
        </motion.div>
      </div>
    </div>
  );
}
